 1	import {
 2	  PageComponentProps,
 3	  useAccessReview,
 4	} from "@openshift-console/dynamic-plugin-sdk";
 5	import { Grid, GridItem, PageSection } from "@patternfly/react-core";
 6	import { SectionHeading } from "copiedFromConsole/utils/headings";
 7	import { Loading } from "copiedFromConsole/utils/status-box";
 8	import { NodeHealthCheckModel } from "data/model";
 9	import { NodeHealthCheck } from "data/types";
10	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
11	import * as React from "react";
12	import { DetailsLeftPane } from "./DetailsLeftPane";
13	import { DetailsRightPane } from "./DetailsRightPane";
14	import { UnhealthyConditionsTable } from "./UnhealthyConditionsTable";
15	
16	const NodeHealthCheckDetailsTab: React.FC<
17	  PageComponentProps<NodeHealthCheck>
18	> = ({ obj: nodeHealthCheck }) => {
19	  const [canUpdateAccess, loading] = useAccessReview({
20	    group: NodeHealthCheckModel.apiGroup,
21	    resource: NodeHealthCheckModel.plural,
22	    verb: "patch",
23	    name: nodeHealthCheck.metadata?.name,
24	  });
25	
26	  const { t } = useNodeHealthCheckTranslation();
27	  if (loading) {
28	    return <Loading />;
29	  }
30	  return (
31	    <>
32	      <PageSection variant="light">
33	        <Grid hasGutter>
34	          <SectionHeading text={t("NodeHealthCheck details")} />
35	          <GridItem span={5}>
36	            <DetailsLeftPane
37	              resource={nodeHealthCheck}
38	              canEdit={!loading && canUpdateAccess}
39	            />
40	          </GridItem>
41	          <GridItem span={1} />
42	          <GridItem span={5}>
43	            <DetailsRightPane nodeHealthCheck={nodeHealthCheck} />
44	          </GridItem>
45	        </Grid>
46	      </PageSection>
47	      <PageSection variant="light">
48	        <SectionHeading text={t("Unhealthy Conditions")} />
49	        <UnhealthyConditionsTable nodeHealthCheck={nodeHealthCheck} />
50	      </PageSection>
51	    </>
52	  );
53	};
54	
55	export default NodeHealthCheckDetailsTab;

